1123: test "Locker: contended" {
1124:     const threads_count = 4;
1125:     const increments = 1000;
1126: 
1127:     const State = struct {
1128:         locker: Locker = .{},
1129:         counter: u32 = 0,
1130:     };
1131: 
1132:     const Runner = struct {
1133:         thread: std.Thread = undefined,
1134:         state: *State,
