10: pub const Packet = extern struct {
11:     pub const Status = enum(u8) {
12:         ok,
13:         too_much_data,
14:         client_evicted,
15:         client_release_too_low,
16:         client_release_too_high,
17:         client_shutdown,
18:         invalid_operation,
19:         invalid_data_size,
20:     };
21: 
22:     /// External packet type exposed to the user.
23:     pub const Extern = extern struct {
24:         user_data: ?*anyopaque,
25:         data: ?*anyopaque,
26:         data_size: u32,
27:         user_tag: u16,
28:         operation: u8,
29:         status: Status,
30:         @"opaque": [64]u8 = @splat(0),
31: 
32:         pub fn cast(self: *Extern) *Packet {
33:             return @ptrCast(self);
34:         }
35:     };
36: 
37:     const Phase = enum(u8) {
38:         submitted,
39:         pending,
40:         batched,
41:         sent,
42:         complete,
43:     };
44: 
45:     pub const Queue = QueueType(Packet);
46: 
47:     user_data: ?*anyopaque,
48:     data: ?*anyopaque,
49:     data_size: u32,
50:     user_tag: u16,
51:     operation: u8,
52:     status: Status,
53: 
54:     link: Queue.Link,
55: 
56:     multi_batch_time_monotonic: u64,
57:     multi_batch_next: ?*Packet,
58:     multi_batch_tail: ?*Packet,
59:     multi_batch_count: u16,
60:     multi_batch_event_count: u16,
61:     multi_batch_result_count_expected: u16,
62:     phase: Phase,
63:     reserved: [25]u8 = @splat(0),
64: 
65:     pub fn cast(self: *Packet) *Extern {
66:         return @ptrCast(self);
67:     }
68: 
69:     pub fn slice(packet: *const Packet) []const u8 {
70:         if (packet.data_size == 0) {
71:             // It may be an empty array (null pointer)
72:             // or a buffer with no elements (valid pointer and size == 0).
73:             stdx.maybe(packet.data == null);
74:             return &[0]u8{};
75:         }
76: 
77:         const data: [*]const u8 = @ptrCast(packet.data.?);
78:         return data[0..packet.data_size];
79:     }
80: 
81:     /// Asserts the internal state of the packet according to its expected phase.
82:     /// Inline function, so `expected` can be comptime known.
83:     pub inline fn assert_phase(packet: *const Packet, expected: Phase) void {
84:         assert(packet.phase == expected);
85:         assert(packet.data_size == 0 or packet.data != null);
86:         assert(stdx.zeroed(&packet.reserved));
87:         maybe(packet.user_data == null);
88:         maybe(packet.user_tag == 0);
89: 
90:         switch (expected) {
91:             .submitted => {
92:                 assert(packet.link.next == null);
93:                 assert(packet.multi_batch_next == null);
94:                 assert(packet.multi_batch_tail == null);
95:                 assert(packet.multi_batch_count == 0);
96:                 assert(packet.multi_batch_event_count == 0);
97:                 assert(packet.multi_batch_result_count_expected == 0);
98:                 assert(packet.multi_batch_time_monotonic == 0);
99:             },
100:             .pending => {
101:                 assert(packet.multi_batch_count >= 1);
102:                 assert(packet.multi_batch_next == null or packet.multi_batch_count > 1);
103:                 assert((packet.multi_batch_next == null) == (packet.multi_batch_tail == null));
104:                 maybe(packet.data_size == 0);
105:                 maybe(packet.multi_batch_event_count == 0);
106:                 maybe(packet.multi_batch_result_count_expected == 0);
107:                 maybe(packet.link.next == null);
108:                 assert(packet.multi_batch_time_monotonic != 0);
109:             },
110:             .batched => {
111:                 assert(packet.link.next == null);
112:                 assert(packet.multi_batch_tail == null);
113:                 assert(packet.multi_batch_count == 0);
114:                 assert(packet.multi_batch_event_count == 0);
115:                 assert(packet.multi_batch_result_count_expected == 0);
116:                 maybe(packet.multi_batch_next != null);
117:                 assert(packet.multi_batch_time_monotonic == 0);
118:             },
119:             .sent => {
120:                 assert(packet.link.next == null);
121:                 assert(packet.multi_batch_count > 0);
122:                 assert(packet.multi_batch_next == null or packet.multi_batch_count > 1);
123:                 assert((packet.multi_batch_next == null) == (packet.multi_batch_tail == null));
124:                 maybe(packet.multi_batch_event_count == 0);
125:                 maybe(packet.multi_batch_result_count_expected == 0);
126:                 assert(packet.multi_batch_time_monotonic != 0);
127:             },
128:             .complete => {
129:                 // The packet pointer isn't available after completed,
130:                 // it may be deallocated by the user;
131:                 unreachable;
132:             },
133:         }
134:     }
135: 
136:     comptime {
137:         assert(@sizeOf(Extern) % @alignOf(Extern) == 0);
138:         assert(@alignOf(Extern) == 8);
139: 
140:         assert(@sizeOf(Packet) == @sizeOf(Extern));
141:         assert(@alignOf(Packet) == @alignOf(Extern));
142: 
143:         // Asserting the fields are identical.
144:         for (std.meta.fields(Extern)) |field_extern| {
145:             if (std.mem.eql(u8, field_extern.name, "opaque")) continue;
146:             const field_packet = std.meta.fields(Packet)[
147:                 std.meta.fieldIndex(
148:                     Packet,
149:                     field_extern.name,
150:                 ).?
151:             ];
152:             assert(field_packet.type == field_extern.type);
153:             assert(field_packet.alignment == field_extern.alignment);
154:             assert(@offsetOf(Packet, field_extern.name) ==
155:                 @offsetOf(Extern, field_extern.name));
156:         }
157:     }
158: };
