19: // Multiversion interface backed by three different implementations:
20: // - MultiversionOS implements the real dynamic re-execution logic,
21: // - single_version is used when multiversion is disabled (release list of count one),
22: // - VOPR simulation.
23: pub const Multiversion = struct {
24:     context: *anyopaque,
25:     vtable: *const VTable,
26: 
27:     pub const VTable = struct {
28:         releases_bundled: *const fn (context: *anyopaque) ReleaseList,
29:         release_execute: *const fn (context: *anyopaque, release: Release) void,
30:         tick: *const fn (context: *anyopaque) void,
31:     };
32: 
33:     /// A list of all versions of code that are available in the current binary.
34:     /// Includes the current version, newer versions, and older versions.
35:     /// Ordered from lowest/oldest to highest/newest.
36:     /// Can be updated by multiversioning while running.
37:     pub fn releases_bundled(multiversion: Multiversion) ReleaseList {
38:         return multiversion.vtable.releases_bundled(multiversion.context);
39:     }
40: 
41:     /// Replace the currently-running replica with the given release.
42:     ///
43:     /// If called with a `release` that is *not* in `releases_bundled`, the replica should shut
44:     /// down with a helpful error message to warn the operator that they must upgrade.
45:     // NB: this is void for VOPR, but the actual implementation is noreturn.
46:     pub fn release_execute(multiversion: Multiversion, release: Release) void {
47:         multiversion.vtable.release_execute(multiversion.context, release);
48:     }
49: 
50:     pub fn tick(multiversion: Multiversion) void {
51:         multiversion.vtable.tick(multiversion.context);
52:     }
53: 
54:     /// Multiversion implementation that only has one release available.
55:     pub fn single_release(comptime release: Release) Multiversion {
56:         const vtable = struct {
57:             fn releases_bundled(_: *anyopaque) ReleaseList {
58:                 var result: ReleaseList = .empty;
59:                 result.push(release);
60:                 return result;
61:             }
62:             fn release_execute(_: *anyopaque, release_next: Release) void {
63:                 assert(release_next.value != release.value);
64:                 @panic("multiversion unsupported");
65:             }
66:             fn tick(_: *anyopaque) void {}
67:         };
68: 
69:         return .{
70:             .context = @constCast(&{}),
71:             .vtable = &.{
72:                 .releases_bundled = vtable.releases_bundled,
73:                 .release_execute = vtable.release_execute,
74:                 .tick = vtable.tick,
75:             },
76:         };
77:     }
78: };
