120: /// A ReleaseList is ordered from lowest-to-highest.
121: pub const ReleaseList = struct {
122:     buffer: [constants.vsr_releases_max]Release,
123:     count: u16,
124: 
125:     pub const empty: ReleaseList = .{
126:         .buffer = undefined,
127:         .count = 0,
128:     };
129: 
130:     pub fn push(release_list: *ReleaseList, release: Release) void {
131:         assert(release_list.count < constants.vsr_releases_max);
132:         assert(release.value > 0);
133:         if (release_list.count > 0) {
134:             assert(release_list.last().value < release.value);
135:         }
136:         release_list.buffer[release_list.count] = release;
137:         release_list.count += 1;
138:     }
139: 
140:     pub fn slice(release_list: *const ReleaseList) []const Release {
141:         return release_list.buffer[0..release_list.count];
142:     }
143: 
144:     pub fn verify(release_list: *const ReleaseList) void {
145:         assert(release_list.count > 0);
146:         for (release_list.slice()) |a| assert(a.value > 0);
147:         for (
148:             release_list.slice()[0 .. release_list.count - 1],
149:             release_list.slice()[1..],
150:         ) |a, b| {
151:             assert(a.value < b.value); // Sorted and unique.
152:         }
