7: /// Combines a field (the key prefix) with a timestamp (the primary key).
8: /// - To keep alignment, it supports either `u64` or `u128` prefixes (which can be truncated
9: ///   to smaller types to fit the correct field data type).
10: /// - "Deleted" values are denoted by a tombstone bit in the timestamp.
11: /// - It also supports composite keys without a prefix (`Field == void`), which is useful for
12: ///   indexing flags that are only checked with "exists".
13: pub fn CompositeKeyType(comptime Field: type) type {
14:     // The type if zeroed padding is needed.
15:     const Pad = switch (Field) {
16:         void => u0,
17:         u64 => u0,
18:         u128 => u64,
19:         else => @compileError("invalid Field for CompositeKey: " ++ @typeName(Field)),
20:     };
21: 
22:     return extern struct {
23:         const CompositeKey = @This();
24: 
25:         pub const sentinel_key: Key = key_from_value(&.{
26:             .field = if (Field == void) {} else math.maxInt(Field),
27:             .timestamp = math.maxInt(u64),
28:         });
29: 
30:         const tombstone_bit: u64 = 1 << (64 - 1);
31: 
32:         // u128 may be aligned to 8 instead of the expected 16.
33:         const field_bitsize_alignment = @max(
34:             @divExact(@bitSizeOf(Field), 8),
35:             @divExact(@bitSizeOf(u64), 8),
36:         );
37: 
38:         pub const Key = std.meta.Int(
39:             .unsigned,
40:             // Little-endian:
41:             @bitSizeOf(u64) + @bitSizeOf(Field) + @bitSizeOf(Pad),
42:         );
43: 
44:         // NB: ideally, we should swap `field` and `timestamp` here to  maintain
45:         // little-endian order throughout, but we are constrained by existing data.
46:         field: Field align(field_bitsize_alignment),
47:         /// The most significant bit must be unset as it is used to indicate a tombstone.
48:         timestamp: u64,
49:         padding: Pad = 0,
50: 
51:         comptime {
52:             assert(@sizeOf(CompositeKey) == @sizeOf(Key));
53:             assert(@sizeOf(CompositeKey) == switch (Field) {
54:                 void => @sizeOf(u64),
55:                 u64 => @sizeOf(u128),
56:                 u128 => @sizeOf(u256),
57:                 else => unreachable,
58:             });
59:             assert(@alignOf(CompositeKey) >= @alignOf(Field));
60:             assert(@alignOf(CompositeKey) == field_bitsize_alignment);
61:             assert(stdx.no_padding(CompositeKey));
62:         }
63: 
64:         pub inline fn key_from_value(value: *const CompositeKey) Key {
65:             assert(value.padding == 0);
66:             if (Field == void) {
67:                 comptime assert(Key == u64);
68:                 return value.timestamp & ~tombstone_bit;
69:             } else {
70:                 comptime assert(@sizeOf(Key) == @sizeOf(Field) * 2);
71:                 return (@as(Key, value.field) << 64) | @as(Key, value.timestamp & ~tombstone_bit);
72:             }
73:         }
74: 
75:         pub inline fn key_prefix(key: Key) Field {
76:             return if (Field == void) {} else @truncate(key >> 64);
77:         }
78: 
79:         pub inline fn tombstone(value: *const CompositeKey) bool {
80:             assert(value.padding == 0);
81:             return (value.timestamp & tombstone_bit) != 0;
82:         }
83: 
84:         pub inline fn tombstone_from_key(key: Key) CompositeKey {
85:             const timestamp: u64 = @truncate(key);
86:             assert(timestamp & tombstone_bit == 0);
87: 
88:             return .{
89:                 .field = key_prefix(key),
90:                 .timestamp = timestamp | tombstone_bit,
91:             };
92:         }
93:     };
94: }
95: 
96: pub fn is_composite_key(comptime Value: type) bool {
97:     if (@typeInfo(Value) == .@"struct" and
98:         @hasField(Value, "field") and
99:         @hasField(Value, "timestamp"))
100:     {
101:         const Field = @FieldType(Value, "field");
102:         return switch (Field) {
103:             void, u64, u128 => Value == CompositeKeyType(Field),
104:             else => false,
105:         };
106:     }
107: 
108:     return false;
109: }
