399:     pub fn calculate_checksum(superblock: *const SuperBlockHeader) u128 {
400:         comptime assert(meta.fieldIndex(SuperBlockHeader, "checksum") == 0);
401:         comptime assert(meta.fieldIndex(SuperBlockHeader, "checksum_padding") == 1);
402:         comptime assert(meta.fieldIndex(SuperBlockHeader, "copy") == 2);
