309: // Per-client callback invoked every time a `tb_client_submit` completes or is canceled.
310: // Use `packet->userdata` to identify the specific submission.
311: // `result` is null iff `packet->status != TB_PACKET_OK`
312: // `result` is only valid for the duration of the callback itself.
313: typedef void (*tb_completion_t)(
314:     uintptr_t userdata,
315:     tb_packet_t* packet,
316:     uint64_t timestamp,
317:     const uint8_t *result, // nullable
318:     uint32_t result_size
319: );
