321: // Initialize a new TigerBeetle client which connects to the addresses provided and
322: // completes submitted packets by invoking the callback with the given context.
323: TB_INIT_STATUS tb_client_init(
324:     tb_client_t *client_out,
325:     // 128-bit unsigned integer represented as a 16-byte little-endian array.
326:     const uint8_t cluster_id[16],
327:     const char *address_ptr,
328:     uint32_t address_len,
329:     uintptr_t completion_ctx,
330:     tb_completion_t completion_callback
331: );
332: 
333: // Initialize a new TigerBeetle client that echoes back any submitted data.
334: TB_INIT_STATUS tb_client_init_echo(
335:     tb_client_t *client_out,
336:     // 128-bit unsigned integer represented as a 16-byte little-endian array.
337:     const uint8_t cluster_id[16],
338:     const char *address_ptr,
339:     uint32_t address_len,
340:     uintptr_t completion_ctx,
341:     tb_completion_t completion_callback
342: );
343: 
344: // Retrieve the parameters initially passed to `tb_client_init` or `tb_client_init_echo`.
345: // Return value: `TB_CLIENT_OK` on success, or `TB_CLIENT_INVALID` if the client handle was
346: // not initialized or has already been closed.
347: TB_CLIENT_STATUS tb_client_init_parameters(
348:     tb_client_t* client,
349:     tb_init_parameters_t* init_parameters_out
350: );
351: 
352: // Retrieve the callback context initially passed to `tb_client_init` or `tb_client_init_echo`.
353: // Return value: `TB_CLIENT_OK` on success, or `TB_CLIENT_INVALID` if the client handle was
354: // not initialized or has already been closed.
355: TB_CLIENT_STATUS tb_client_completion_context(
356:     tb_client_t* client,
357:     uintptr_t* completion_ctx_out
358: );
359: 
360: // Submit a packet with its `operation`, `data`, and `data_size` fields set.
361: // Once completed, `completion_callback` will be invoked with `completion_ctx`
362: // and the given packet on the `tb_client` thread (separate from the caller's thread).
363: // Return value: `TB_CLIENT_OK` on success, or `TB_CLIENT_INVALID` if the client handle was
364: // not initialized or has already been closed.
365: TB_CLIENT_STATUS tb_client_submit(
366:     tb_client_t *client,
367:     tb_packet_t *packet
368: );
369: 
370: // Closes the client, causing any previously submitted packets to be completed with
371: // `TB_PACKET_CLIENT_SHUTDOWN` before freeing any allocated client resources from init.
372: // Return value: `TB_CLIENT_OK` on success, or `TB_CLIENT_INVALID` if the client handle was
373: // not initialized or has already been closed.
374: TB_CLIENT_STATUS tb_client_deinit(
375:     tb_client_t *client
376: );
377: 
378: // Registers or unregisters the application log callback.
379: TB_REGISTER_LOG_CALLBACK_STATUS tb_client_register_log_callback(
380:     void (*callback)(TB_LOG_LEVEL, const uint8_t*, uint32_t),
381:     bool debug
382: );
