79: pub fn init_error_to_status(err: tb.InitError) tb_init_status {
80:     return switch (err) {
81:         error.Unexpected => .unexpected,
82:         error.OutOfMemory => .out_of_memory,
83:         error.AddressInvalid => .address_invalid,
84:         error.AddressLimitExceeded => .address_limit_exceeded,
85:         error.SystemResources => .system_resources,
86:         error.NetworkSubsystemFailed => .network_subsystem,
87:     };
88: }
