90: pub fn init(
91:     tb_client_out: *tb_client_t,
92:     cluster_id_ptr: *const [16]u8,
93:     addresses_ptr: [*:0]const u8,
94:     addresses_len: u32,
95:     completion_ctx: usize,
96:     completion_callback: tb_completion_t,
97: ) callconv(.c) tb_init_status {
98:     const addresses = @as([*]const u8, @ptrCast(addresses_ptr))[0..addresses_len];
99: 
100:     // Passing u128 by value is prone to ABI issues. Pass as a [16]u8, and explicitly copy into
101:     // memory we know will be aligned correctly. Don't just use bytesToValue here, as that keeps
102:     // pointer alignment, and will result in a potentially unaligned access of a
103:     // `*align(1) const u128`.
104:     const cluster_id: u128 = blk: {
105:         var cluster_id: u128 = undefined;
106:         stdx.copy_disjoint(.exact, u8, std.mem.asBytes(&cluster_id), cluster_id_ptr);
107: 
108:         break :blk cluster_id;
109:     };
110: 
111:     tb.init(
112:         std.heap.c_allocator,
113:         tb_client_out.cast(),
114:         cluster_id,
115:         addresses,
116:         completion_ctx,
117:         completion_callback,
118:     ) catch |err| return init_error_to_status(err);
119:     return .success;
120: }
