125:     addresses_ptr: [*:0]const u8,
126:     addresses_len: u32,
127:     completion_ctx: usize,
128:     completion_callback: tb_completion_t,
129: ) callconv(.c) tb_init_status {
130:     const addresses = @as([*]const u8, @ptrCast(addresses_ptr))[0..addresses_len];
131: 
132:     // See explanation in init().
133:     const cluster_id: u128 = blk: {
134:         var cluster_id: u128 = undefined;
135:         stdx.copy_disjoint(.exact, u8, std.mem.asBytes(&cluster_id), cluster_id_ptr);
136: 
137:         break :blk cluster_id;
138:     };
139: 
140:     tb.init_echo(
141:         std.heap.c_allocator,
142:         tb_client_out.cast(),
143:         cluster_id,
144:         addresses,
145:         completion_ctx,
