151: pub fn submit(tb_client: ?*tb_client_t, packet: *tb_packet_t) callconv(.c) tb_client_status {
152:     const client: *tb.ClientInterface = if (tb_client) |ptr| ptr.cast() else return .invalid;
153:     client.submit(packet) catch |err| switch (err) {
154:         error.ClientInvalid => return .invalid,
155:     };
156:     return .ok;
157: }
