189: pub fn register_log_callback(
190:     callback_maybe: ?Logging.Callback,
191:     debug: bool,
192: ) callconv(.c) tb_register_log_callback_status {
193:     Logging.global.mutex.lock();
194:     defer Logging.global.mutex.unlock();
195: 
196:     if (Logging.global.callback == null) {
197:         if (callback_maybe) |callback| {
198:             Logging.global.callback = callback;
199:             Logging.global.debug = debug;
200:             return .success;
201:         } else {
202:             return .not_registered;
203:         }
204:     } else {
205:         if (callback_maybe == null) {
206:             Logging.global.callback = null;
207:             Logging.global.debug = debug;
208:             return .success;
209:         } else {
210:             return .already_registered;
211:         }
212:     }
213: }
214: 
215: pub const Logging = struct {
216:     const Callback = *const fn (
217:         message_level: tb_log_level,
218:         message_ptr: [*]const u8,
219:         message_len: u32,
220:     ) callconv(.c) void;
221: 
222:     const log_line_max = 8192;
223: 
224:     /// Logging is global per process; it would be nice to be able to define a different logger
225:     /// for each client instance, though.
226:     var global: Logging = .{};
227: 
228:     callback: ?Callback = null,
229:     mutex: std.Thread.Mutex = .{},
230:     buffer: [log_line_max]u8 = undefined,
231:     debug: bool = false,
232: 
233:     /// A logger which defers to an application provided handler.
234:     pub fn application_logger(
235:         comptime message_level: std.log.Level,
236:         comptime scope: @Type(.enum_literal),
237:         comptime format: []const u8,
238:         args: anytype,
239:     ) void {
240:         // Debug logs are dropped here unless debug is set, because of the potential penalty in
241:         // crossing FFI to drop them.
242:         if (message_level == .debug and !Logging.global.debug) {
243:             return;
244:         }
245: 
246:         // Other messages are silently dropped if no logging callback is specified - unless they're
247:         // warn or err. The value in having those for debugging is too high to silence them, even
248:         // until client libraries catch up and implement a callback handler.
249:         if (Logging.global.callback == null and (message_level == .warn or message_level == .err)) {
250:             std.log.defaultLog(message_level, scope, format, args);
251:             return;
252:         }
253: 
254:         // Protect everything with a mutex - logging can be called from different threads
255:         // simultaneously, and there's only one buffer for now.
256:         Logging.global.mutex.lock();
257:         defer Logging.global.mutex.unlock();
258: 
259:         const callback = Logging.global.callback orelse return;
260: 
261:         const tb_message_level: tb_log_level = @enumFromInt(@intFromEnum(message_level));
262:         const prefix = if (scope == .default) ": " else "(" ++ @tagName(scope) ++ "): ";
263:         const output = std.fmt.bufPrint(
264:             &Logging.global.buffer,
265:             prefix ++ format,
266:             args,
267:         ) catch |err| switch (err) {
268:             error.NoSpaceLeft => blk: {
269:                 // Print an error indicating the log message has been truncated, before the
270:                 // truncated log itself.
271:                 const message = "the following log message has been truncated:";
272:                 callback(tb_message_level, message.ptr, message.len);
273: 
274:                 break :blk &Logging.global.buffer;
275:             },
276:             else => unreachable,
277:         };
278: 
279:         callback(tb_message_level, output.ptr, @intCast(output.len));
280:     }
281: };
