42: fn resolve_c_type(comptime Type: type) []const u8 {
43:     switch (@typeInfo(Type)) {
44:         .array => |info| return resolve_c_type(info.child),
45:         .@"enum" => |info| return resolve_c_type(info.tag_type),
46:         .@"struct" => return resolve_c_type(std.meta.Int(.unsigned, @bitSizeOf(Type))),
47:         .bool => return "uint8_t",
48:         .int => |info| {
49:             assert(info.signedness == .unsigned);
50:             return switch (info.bits) {
51:                 8 => "uint8_t",
52:                 16 => "uint16_t",
53:                 32 => "uint32_t",
54:                 64 => "uint64_t",
55:                 128 => "tb_uint128_t",
56:                 else => @compileError("invalid int type"),
57:             };
58:         },
59:         .optional => |info| switch (@typeInfo(info.child)) {
60:             .pointer => return resolve_c_type(info.child),
61:             else => @compileError("Unsupported optional type: " ++ @typeName(Type)),
62:         },
63:         .pointer => |info| {
64:             assert(info.size != .slice);
65:             assert(!info.is_allowzero);
66: 
67:             inline for (type_mappings) |type_mapping| {
68:                 const ZigType = type_mapping[0];
69:                 const c_name = type_mapping[1];
70: 
71:                 if (info.child == ZigType) {
72:                     const prefix = if (@typeInfo(ZigType) == .@"struct") "struct " else "";
73:                     return prefix ++ c_name ++ "*";
74:                 }
75:             }
76: 
77:             return comptime resolve_c_type(info.child) ++ "*";
78:         },
79:         .void, .@"opaque" => return "void",
80:         else => @compileError("Unhandled type: " ++ @typeName(Type)),
81:     }
82: }
