84: fn to_uppercase(comptime input: []const u8) [input.len]u8 {
85:     comptime var output: [input.len]u8 = undefined;
86:     inline for (&output, 0..) |*char, i| {
87:         char.* = input[i];
88:         char.* -= 32 * @as(u8, @intFromBool(char.* >= 'a' and char.* <= 'z'));
89:     }
90:     return output;
91: }
