93: fn emit_enum(
94:     buffer: *std.ArrayList(u8),
95:     comptime Type: type,
96:     comptime type_info: anytype,
97:     comptime c_name: []const u8,
98:     comptime skip_fields: []const []const u8,
99: ) !void {
100:     var suffix_pos = std.mem.lastIndexOfScalar(u8, c_name, '_').?;
101:     if (std.mem.count(u8, c_name, "_") == 1) suffix_pos = c_name.len;
102: 
103:     try buffer.writer().print("typedef enum {s} {{\n", .{c_name});
104: 
105:     inline for (type_info.fields, 0..) |field, i| {
106:         if (comptime std.mem.startsWith(u8, field.name, "deprecated_")) continue;
107:         comptime var skip = false;
108:         inline for (skip_fields) |sf| {
109:             skip = skip or comptime std.mem.eql(u8, sf, field.name);
110:         }
111: 
112:         if (!skip) {
113:             const field_name = to_uppercase(field.name);
114:             if (@typeInfo(Type) == .@"enum") {
115:                 const int_value = @intFromEnum(@field(Type, field.name));
116:                 try buffer.writer().print("    {s}_{s} = {s},\n", .{
117:                     c_name[0..suffix_pos],
118:                     @as([]const u8, &field_name),
119:                     if (int_value == std.math.maxInt(@TypeOf(int_value)))
120:                         std.fmt.comptimePrint("0x{X}", .{int_value})
121:                     else
122:                         std.fmt.comptimePrint("{}", .{int_value}),
123:                 });
124:             } else {
125:                 // Packed structs.
126:                 try buffer.writer().print("    {s}_{s} = 1 << {},\n", .{
127:                     c_name[0..suffix_pos],
128:                     @as([]const u8, &field_name),
129:                     i,
130:                 });
131:             }
132:         }
133:     }
134: 
135:     try buffer.writer().print("}} {s};\n\n", .{c_name});
136: }
137: 
138: fn emit_struct(
139:     buffer: *std.ArrayList(u8),
140:     comptime type_info: anytype,
141:     comptime c_name: []const u8,
142: ) !void {
143:     try buffer.writer().print("typedef struct {s} {{\n", .{c_name});
144: 
145:     inline for (type_info.fields) |field| {
146:         try buffer.writer().print("    {s} {s}", .{
147:             resolve_c_type(field.type),
148:             field.name,
149:         });
150: 
151:         switch (@typeInfo(field.type)) {
152:             .array => |array| try buffer.writer().print("[{d}]", .{array.len}),
153:             else => {},
154:         }
155: 
156:         try buffer.writer().print(";\n", .{});
157:     }
158: 
159:     try buffer.writer().print("}} {s};\n\n", .{c_name});
160: }
