162: pub fn main() !void {
163:     @setEvalBranchQuota(100_000);
164: 
165:     var arena = std.heap.ArenaAllocator.init(std.heap.page_allocator);
166:     defer arena.deinit();
167: 
168:     const allocator = arena.allocator();
169: 
170:     var buffer = std.ArrayList(u8).init(allocator);
171:     try buffer.writer().print(
172:         \\ //////////////////////////////////////////////////////////
173:         \\ // This file was auto-generated by tb_client_header.zig //
174:         \\ //              Do not manually modify.                 //
175:         \\ //////////////////////////////////////////////////////////
176:         \\
177:         \\#ifndef TB_CLIENT_H
178:         \\#define TB_CLIENT_H
179:         \\
180:         \\#ifdef __cplusplus
181:         \\extern "C" {{
182:         \\#endif
183:         \\
184:         \\#include <stddef.h>
185:         \\#include <stdint.h>
186:         \\#include <stdbool.h>
187:         \\
188:         \\typedef __uint128_t tb_uint128_t;
189:         \\
190:         \\
191:     , .{});
192: 
193:     // Emit C type declarations.
194:     inline for (type_mappings) |type_mapping| {
195:         const ZigType = type_mapping[0];
196:         const c_name = type_mapping[1];
197:         if (type_mapping.len == 3) {
198:             const comments: []const u8 = type_mapping[2];
199:             try buffer.writer().print(comments, .{});
200:             try buffer.writer().print("\n", .{});
201:         }
202: 
203:         switch (@typeInfo(ZigType)) {
204:             .@"struct" => |info| switch (info.layout) {
205:                 .auto => @compileError("Invalid C struct type: " ++ @typeName(ZigType)),
206:                 .@"packed" => try emit_enum(&buffer, ZigType, info, c_name, &.{"padding"}),
207:                 .@"extern" => try emit_struct(&buffer, info, c_name),
208:             },
209:             .@"enum" => |info| {
210:                 comptime var skip: []const []const u8 = &.{};
211:                 if (ZigType == exports.tb_operation) {
212:                     skip = &.{ "reserved", "root", "register" };
213:                 }
214: 
215:                 try emit_enum(&buffer, ZigType, info, c_name, skip);
216:             },
217:             else => try buffer.writer().print("typedef {s} {s}; \n\n", .{
218:                 resolve_c_type(ZigType),
219:                 c_name,
220:             }),
221:         }
222:     }
223: 
224:     // Emit C function declarations.
225:     // TODO: use `std.meta.declaractions` and generate with pub + export functions.
226:     // Zig 0.9.1 has `decl.data.Fn.arg_names` but it's currently/incorrectly a zero-sized slice.
227:     try buffer.writer().print(
228:         \\// Per-client callback invoked every time a `tb_client_submit` completes or is canceled.
229:         \\// Use `packet->userdata` to identify the specific submission.
230:         \\// `result` is null iff `packet->status != TB_PACKET_OK`
231:         \\// `result` is only valid for the duration of the callback itself.
232:         \\typedef void (*tb_completion_t)(
233:         \\    uintptr_t userdata,
234:         \\    tb_packet_t* packet,
235:         \\    uint64_t timestamp,
236:         \\    const uint8_t *result, // nullable
237:         \\    uint32_t result_size
238:         \\);
239:         \\
240:         \\// Initialize a new TigerBeetle client which connects to the addresses provided and
241:         \\// completes submitted packets by invoking the callback with the given context.
242:         \\TB_INIT_STATUS tb_client_init(
243:         \\    tb_client_t *client_out,
244:         \\    // 128-bit unsigned integer represented as a 16-byte little-endian array.
245:         \\    const uint8_t cluster_id[16],
246:         \\    const char *address_ptr,
247:         \\    uint32_t address_len,
248:         \\    uintptr_t completion_ctx,
249:         \\    tb_completion_t completion_callback
250:         \\);
251:         \\
252:         \\// Initialize a new TigerBeetle client that echoes back any submitted data.
253:         \\TB_INIT_STATUS tb_client_init_echo(
254:         \\    tb_client_t *client_out,
255:         \\    // 128-bit unsigned integer represented as a 16-byte little-endian array.
256:         \\    const uint8_t cluster_id[16],
257:         \\    const char *address_ptr,
258:         \\    uint32_t address_len,
259:         \\    uintptr_t completion_ctx,
260:         \\    tb_completion_t completion_callback
261:         \\);
262:         \\
263:         \\// Retrieve the parameters initially passed to `tb_client_init` or `tb_client_init_echo`.
264:         \\// Return value: `TB_CLIENT_OK` on success, or `TB_CLIENT_INVALID` if the client handle was
265:         \\// not initialized or has already been closed.
266:         \\TB_CLIENT_STATUS tb_client_init_parameters(
267:         \\    tb_client_t* client,
268:         \\    tb_init_parameters_t* init_parameters_out
269:         \\);
270:         \\
271:         \\// Retrieve the callback context initially passed to `tb_client_init` or `tb_client_init_echo`.
272:         \\// Return value: `TB_CLIENT_OK` on success, or `TB_CLIENT_INVALID` if the client handle was
273:         \\// not initialized or has already been closed.
274:         \\TB_CLIENT_STATUS tb_client_completion_context(
275:         \\    tb_client_t* client,
276:         \\    uintptr_t* completion_ctx_out
277:         \\);
278:         \\
279:         \\// Submit a packet with its `operation`, `data`, and `data_size` fields set.
280:         \\// Once completed, `completion_callback` will be invoked with `completion_ctx`
281:         \\// and the given packet on the `tb_client` thread (separate from the caller's thread).
282:         \\// Return value: `TB_CLIENT_OK` on success, or `TB_CLIENT_INVALID` if the client handle was
283:         \\// not initialized or has already been closed.
284:         \\TB_CLIENT_STATUS tb_client_submit(
285:         \\    tb_client_t *client,
286:         \\    tb_packet_t *packet
287:         \\);
288:         \\
289:         \\// Closes the client, causing any previously submitted packets to be completed with
290:         \\// `TB_PACKET_CLIENT_SHUTDOWN` before freeing any allocated client resources from init.
291:         \\// Return value: `TB_CLIENT_OK` on success, or `TB_CLIENT_INVALID` if the client handle was
292:         \\// not initialized or has already been closed.
293:         \\TB_CLIENT_STATUS tb_client_deinit(
