299:         \\    void (*callback)(TB_LOG_LEVEL, const uint8_t*, uint32_t),
300:         \\    bool debug
301:         \\);
302:         \\
303:         \\
304:     , .{});
305: 
306:     try buffer.writer().print(
307:         \\#ifdef __cplusplus
308:         \\}} // extern "C"
309:         \\#endif
310:         \\
311:         \\#endif // TB_CLIENT_H
312:         \\
313:     , .{});
314: 
315:     try std.io.getStdOut().writeAll(buffer.items);
316: }
