110: pub fn from_seed(seed: u64) PRNG {
111:     var s = seed;
112:     return .{ .s = .{
113:         split_mix_64(&s),
114:         split_mix_64(&s),
115:         split_mix_64(&s),
116:         split_mix_64(&s),
117:     } };
118: }
119: 
120: pub fn from_seed_testing() PRNG {
121:     comptime assert(@import("builtin").is_test);
122:     return .from_seed(std.testing.random_seed);
123: }
