125: fn split_mix_64(s: *u64) u64 {
126:     s.* +%= 0x9e3779b97f4a7c15;
127: 
128:     var z = s.*;
129:     z = (z ^ (z >> 30)) *% 0xbf58476d1ce4e5b9;
130:     z = (z ^ (z >> 27)) *% 0x94d049bb133111eb;
131:     return z ^ (z >> 31);
132: }
133: 
134: fn next(prng: *PRNG) u64 {
135:     const r = std.math.rotl(u64, prng.s[0] +% prng.s[3], 23) +% prng.s[0];
136: 
137:     const t = prng.s[1] << 17;
138: 
139:     prng.s[2] ^= prng.s[0];
140:     prng.s[3] ^= prng.s[1];
141:     prng.s[1] ^= prng.s[2];
142:     prng.s[0] ^= prng.s[3];
143: 
144:     prng.s[2] ^= t;
145: 
146:     prng.s[3] = math.rotl(u64, prng.s[3], 45);
147: 
148:     return r;
149: }
