162: pub fn fill(prng: *PRNG, target: []u8) void {
163:     var i: usize = 0;
164:     const aligned_len = target.len - (target.len & 7);
165: 
166:     // Complete 8 byte segments.
167:     while (i < aligned_len) : (i += 8) {
168:         var n = prng.next();
169:         comptime var j: usize = 0;
170:         inline while (j < 8) : (j += 1) {
171:             target[i + j] = @as(u8, @truncate(n));
172:             n >>= 8;
173:         }
174:     }
175: 
176:     // Remaining (cuts the stream).
177:     if (i != target.len) {
178:         var n = prng.next();
179:         while (i < target.len) : (i += 1) {
180:             target[i] = @as(u8, @truncate(n));
181:             n >>= 8;
182:         }
183:     }
184: }
