213: /// Generate an unbiased, uniformly distributed integer r such that 0 ≤ r ≤ max.
214: ///
215: /// No biased version is provided --- while biased generation is simpler&faster, the bias can be
216: /// quite high depending on max!
217: pub fn int_inclusive(prng: *PRNG, Int: anytype, max: Int) Int {
218:     comptime assert(@typeInfo(Int).int.signedness == .unsigned);
219:     if (max == std.math.maxInt(Int)) {
220:         return prng.int(Int);
221:     }
222: 
223:     comptime assert(@typeInfo(Int).int.signedness == .unsigned);
224:     const bits = @typeInfo(Int).int.bits;
225:     const less_than = max + 1;
226: 
227:     // adapted from:
228:     //   http://www.pcg-random.org/posts/bounded-rands.html
229:     //   "Lemire's (with an extra tweak from Zig)"
230:     var x = prng.int(Int);
231:     var m = math.mulWide(Int, x, less_than);
232:     var l: Int = @truncate(m);
233:     if (l < less_than) {
234:         var t = -%less_than;
235: 
236:         if (t >= less_than) {
237:             t -= less_than;
238:             if (t >= less_than) {
239:                 t %= less_than;
240:             }
241:         }
242:         while (l < t) {
243:             x = prng.int(Int);
244:             m = math.mulWide(Int, x, less_than);
245:             l = @truncate(m);
246:         }
247:     }
248:     return @intCast(m >> bits);
249: }
