311: /// Generates a uniform, unbiased integer r such that max ≤ r ≤ max.
312: pub fn range_inclusive(prng: *PRNG, Int: type, min: Int, max: Int) Int {
313:     comptime assert(@typeInfo(Int).int.signedness == .unsigned);
314:     assert(min <= max);
315:     return min + prng.int_inclusive(Int, max - min);
316: }
