333: /// Returns a uniformly distributed integer of type T.
334: ///
335: /// That is, fills @sizeOf(T) bytes with random bits.
336: pub fn int(prng: *PRNG, Int: type) Int {
337:     comptime assert(@typeInfo(Int).int.signedness == .unsigned);
338:     if (Int == u64) return prng.next();
339:     if (@sizeOf(Int) < @sizeOf(u64)) return @truncate(prng.next());
340:     var result: Int = undefined;
341:     prng.fill(std.mem.asBytes(&result));
342:     return result;
343: }
