403: /// Returns true with the given rational probability.
404: pub fn chance(prng: *PRNG, probability: Ratio) bool {
405:     assert(probability.denominator > 0);
406:     assert(probability.numerator <= probability.denominator);
407:     return prng.int_inclusive(u64, probability.denominator - 1) < probability.numerator;
