475: /// Returns a random value of an enum, where probability is proportional to weight.
476: pub fn enum_weighted(prng: *PRNG, Enum: type, weights: EnumWeightsType(Enum)) Enum {
477:     return enum_weighted_impl(prng, Enum, weights);
478: }
