480: fn enum_weighted_impl(prng: *PRNG, Enum: type, weights: anytype) Enum {
481:     const fields = @typeInfo(Enum).@"enum".fields;
482:     var total: u64 = 0;
483:     inline for (fields) |field| {
484:         total += @field(weights, field.name);
485:     }
486:     assert(total > 0);
487:     var pick = prng.int_inclusive(u64, total - 1);
488:     inline for (fields) |field| {
489:         const weight = @field(weights, field.name);
490:         if (pick < weight) return @as(Enum, @enumFromInt(field.value));
491:         pick -= weight;
492:     }
493:     unreachable;
494: }
