512: /// Return a distribution for use with `random_enum`.
513: ///
514: /// This is swarm testing: some variants are disabled completely,
515: /// and the rest have wildly different probabilities.
516: pub fn enum_weights(
517:     prng: *PRNG,
518:     comptime Enum: type,
519: ) EnumWeightsType(Enum) {
520:     const fields = comptime std.meta.fieldNames(Enum);
521: 
522:     var combination = PRNG.Combination.init(.{
523:         .total = fields.len,
524:         .sample = prng.range_inclusive(u32, 1, fields.len),
525:     });
526:     defer assert(combination.done());
527: 
528:     var weights: PRNG.EnumWeightsType(Enum) = undefined;
529:     inline for (fields) |field| {
530:         @field(weights, field) = if (combination.take(prng))
531:             prng.range_inclusive(u64, 1, 100)
532:         else
533:             0;
534:     }
535: 
536:     return weights;
537: }
