539: /// An iterator-style API for selecting a random combination of elements.
540: pub const Combination = struct {
541:     total: u32,
542:     sample: u32,
543: 
544:     taken: u32,
545:     seen: u32,
546: 
547:     pub fn init(options: struct { total: u32, sample: u32 }) Combination {
548:         assert(options.sample <= options.total);
549:         return .{
550:             .total = options.total,
551:             .sample = options.sample,
552:             .taken = 0,
553:             .seen = 0,
554:         };
555:     }
556: 
557:     pub fn done(combination: *const Combination) bool {
558:         return combination.taken == combination.sample and
559:             combination.seen == combination.total;
560:     }
561: 
562:     pub fn take(combination: *Combination, prng: *PRNG) bool {
563:         assert(combination.seen < combination.total);
564:         assert(combination.taken <= combination.sample);
565: 
566:         const n = combination.total - combination.seen;
567:         const k = combination.sample - combination.taken;
568:         const result = prng.chance(ratio(k, n));
569: 
570:         combination.seen += 1;
571:         if (result) combination.taken += 1;
572:         return result;
573:     }
574: };
