643: pub fn shuffle(prng: *PRNG, T: type, slice: []T) void {
644:     for (0..slice.len) |i| {
645:         const j = prng.int_inclusive(u64, i);
646:         std.mem.swap(T, &slice[i], &slice[j]);
647:     }
