51: pub inline fn div_ceil(numerator: anytype, denominator: anytype) @TypeOf(numerator, denominator) {
52:     comptime {
53:         switch (@typeInfo(@TypeOf(numerator))) {
54:             .int => |int| assert(int.signedness == .unsigned),
55:             .comptime_int => assert(numerator >= 0),
56:             else => @compileError("div_ceil: invalid numerator type"),
57:         }
58: 
59:         switch (@typeInfo(@TypeOf(denominator))) {
60:             .int => |int| assert(int.signedness == .unsigned),
61:             .comptime_int => assert(denominator > 0),
62:             else => @compileError("div_ceil: invalid denominator type"),
63:         }
64:     }
65: 
66:     assert(denominator > 0);
67: 
68:     if (numerator == 0) return 0;
69:     return @divFloor(numerator - 1, denominator) + 1;
70: }
