91: pub inline fn copy_left(
92:     comptime precision: SizePrecision,
93:     comptime T: type,
94:     target: []T,
95:     source: []const T,
96: ) void {
97:     switch (precision) {
98:         .exact => assert(target.len == source.len),
99:         .inexact => assert(target.len >= source.len),
100:     }
101: 
102:     if (!disjoint_slices(T, T, target, source)) {
103:         assert(@intFromPtr(target.ptr) < @intFromPtr(source.ptr));
104:     }
105: 
106:     // (Bypass tidy's ban.)
107:     const copyForwards = std.mem.copyForwards;
108:     copyForwards(T, target, source);
109: }
