287: /// Splits the `haystack` around the first occurrence of `needle`, returning parts before and after.
288: ///
289: /// This is a Zig version of Go's `string.Cut` / Rust's `str::split_once`. Cut turns out to be a
290: /// surprisingly versatile primitive for ad-hoc string processing. Often `std.mem.indexOf` and
291: /// `std.mem.split` can be replaced with a shorter and clearer code using  `cut`.
292: pub fn cut(haystack: []const u8, needle: []const u8) ?struct { []const u8, []const u8 } {
293:     const index = std.mem.indexOf(u8, haystack, needle) orelse return null;
294: 
295:     return .{ haystack[0..index], haystack[index + needle.len ..] };
296: }
