881: /// Return a Formatter for a u64 value representing a file size.
882: /// This formatter statically checks that the number is a multiple of 1024,
883: /// and represents it using the IEC measurement units (KiB, MiB, GiB, ...).
884: pub fn fmt_int_size_bin_exact(comptime value: u64) std.fmt.Formatter(format_int_size_bin_exact) {
885:     comptime assert(value < 1024 or value % 1024 == 0);
886:     return .{ .data = value };
887: }
888: 
889: fn format_int_size_bin_exact(
890:     value: u64,
891:     comptime fmt: []const u8,
892:     options: std.fmt.FormatOptions,
893:     writer: anytype,
894: ) !void {
895:     _ = fmt;
896:     if (value == 0) {
897:         return std.fmt.formatBuf("0B", options, writer);
898:     }
899: 
900:     // The worst case in terms of space needed is 20 bytes,
901:     // since `maxInt(u64)` is the highest number,
902:     // + 3 bytes for the measurement units suffix.
903:     comptime assert(std.fmt.comptimePrint("{}GiB", .{std.math.maxInt(u64)}).len == 23);
904:     var buf: [23]u8 = undefined;
905: 
906:     var magnitude: u8 = 0;
907:     var value_unit = value;
908:     while (value_unit % 1024 == 0) : (magnitude += 1) {
909:         value_unit = @divExact(value_unit, 1024);
910:     }
911: 
912:     const magnitudes_iec = "BKMGTPEZY";
913:     const suffix = magnitudes_iec[magnitude];
914: 
915:     const length: usize = length: {
916:         const i = std.fmt.formatIntBuf(&buf, value_unit, 10, .lower, .{});
917:         if (magnitude == 0) {
918:             buf[i] = suffix;
919:             break :length i + 1;
920:         } else {
921:             buf[i..][0..3].* = [_]u8{ suffix, 'i', 'B' };
922:             break :length i + 3;
923:         }
924:     };
925: 
926:     return std.fmt.formatBuf(buf[0..length], options, writer);
927: }
