995: /// NB: intended for parsing CLI arguments where we care to preserve the user-specified unit.
996: /// Use `size: u64` for all other use-cases.
997: pub const ByteSize = struct {
998:     value: u64,
999:     unit: Unit = .bytes,
1000: 
1001:     const Unit = enum(u64) {
1002:         bytes = 1,
1003:         kib = KiB,
1004:         mib = MiB,
1005:         gib = GiB,
1006:         tib = TiB,
1007:     };
1008: 
1009:     pub fn parse_flag_value(
1010:         string: []const u8,
1011:         static_diagnostic: *?[]const u8,
1012:     ) error{InvalidFlagValue}!ByteSize {
1013:         assert(string.len != 0);
1014: 
1015:         const split_index = for (string, 0..) |c, index| {
1016:             if (std.ascii.isDigit(c) or c == '_') {
1017:                 // Numeric part continues.
1018:             } else break index;
1019:         } else string.len;
1020: 
1021:         const string_amount = string[0..split_index];
1022:         const string_unit = string[split_index..];
1023:         maybe(string_amount.len == 0);
1024:         maybe(string_unit.len == 0);
1025: 
1026:         const amount = std.fmt.parseUnsigned(u64, string_amount, 10) catch |err| switch (err) {
1027:             error.Overflow => {
1028:                 static_diagnostic.* = "value exceeds 64-bit unsigned integer:";
1029:                 return error.InvalidFlagValue;
1030:             },
1031:             error.InvalidCharacter => {
1032:                 static_diagnostic.* = "expected a size, but found:";
1033:                 return error.InvalidFlagValue;
1034:             },
1035:         };
1036: 
1037:         const unit = if (string_unit.len == 0)
1038:             .bytes
1039:         else inline for (comptime std.enums.values(Unit)) |tag| {
1040:             if (std.ascii.eqlIgnoreCase(string_unit, @tagName(tag))) break tag;
1041:         } else {
1042:             static_diagnostic.* = "invalid unit in size, needed KiB, MiB, GiB or TiB:";
1043:             return error.InvalidFlagValue;
1044:         };
1045: 
1046:         _ = std.math.mul(u64, amount, @intFromEnum(unit)) catch {
1047:             static_diagnostic.* = "size in bytes exceeds 64-bit unsigned integer:";
1048:             return error.InvalidFlagValue;
1049:         };
1050: 
1051:         return .{ .value = amount, .unit = unit };
1052:     }
1053: 
1054:     pub fn bytes(size: *const ByteSize) u64 {
1055:         return std.math.mul(
1056:             u64,
1057:             size.value,
1058:             @intFromEnum(size.unit),
1059:         ) catch unreachable;
1060:     }
1061: 
1062:     pub fn suffix(size: *const ByteSize) []const u8 {
1063:         return switch (size.unit) {
1064:             .bytes => "",
1065:             .kib => "KiB",
1066:             .mib => "MiB",
1067:             .gib => "GiB",
1068:             .tib => "TiB",
1069:         };
1070:     }
1071: };
